import { useEffect, useRef, useState } from 'react'
import './App.css'
import pkg from '../package.json'
const PLAYER_LOGO_DATA = "data:image/png;base64,";

const PUZZLE_PIECES = 108
const LEVELS = {
  108: [12, 9],
  150: [15, 10],
}
const IMG = '/puzzle.jpg'
const PIECE_FIT_SFX = '/sounds/piece-fit.mp3'
const PIECE_FIT_VOLUME = 0.5
const PIECE_SPAWN_SFX = '/sounds/piece-spawn.mp3'
const PIECE_SPAWN_VOLUME = 0.45
const PIECE_CONNECT_SFX = '/sounds/piece-connect.mp3'
const PIECE_CONNECT_VOLUME = 0.45
const CAMERA_DELAY_AFTER_PIECE_FIT = 120
const LEGACY_PUZZLE_STATE_STORAGE_KEY = 'muum-puzzle-state-v1'
const PROGRESS_SAVE_STORAGE_KEY = 'muum-puzzle-progress-v1'
const COMPLETE_SAVE_STORAGE_KEY = 'muum-puzzle-complete-v1'
const DOOR_OPEN_SFX = '/sounds/door-open.mp3'
const FOOT_STEP_SFX = '/sounds/foot.mp3'

const TRACKS = [
  { title: '갈림길', src: '/music/crossroads.mp3' },
  { title: '날개', src: '/music/wings.mp3' },
  { title: '몽상', src: '/music/daydream.mp3' },
  { title: '연희동 뒷골목', src: '/music/yeonhui-alley.mp3' },
]

const APP_VERSION_LABEL = `Alpha v${pkg.version}`

function shuffledIndexes(avoidFirst = null) {
  const indexes = TRACKS.map((_, index) => index)
  for (let index = indexes.length - 1; index > 0; index -= 1) {
    const swapIndex = Math.floor(Math.random() * (index + 1))
    ;[indexes[index], indexes[swapIndex]] = [indexes[swapIndex], indexes[index]]
  }
  if (avoidFirst != null && indexes.length > 1 && indexes[0] === avoidFirst) {
    ;[indexes[0], indexes[1]] = [indexes[1], indexes[0]]
  }
  return indexes
}

function fmt(sec) {
  return `${String(Math.floor(sec / 60)).padStart(2, '0')}:${String(sec % 60).padStart(2, '0')}`
}

function readStorageJSON(storageKey) {
  try {
    const raw = localStorage.getItem(storageKey)
    if (!raw) return null
    const parsed = JSON.parse(raw)
    return parsed && typeof parsed === 'object' ? parsed : null
  } catch (error) {
    return null
  }
}

function writeStorageJSON(storageKey, value) {
  try {
    localStorage.setItem(storageKey, JSON.stringify(value))
  } catch (error) {}
}

function removeStorageKey(storageKey) {
  try {
    localStorage.removeItem(storageKey)
  } catch (error) {}
}

function clearProgressSave() {
  removeStorageKey(PROGRESS_SAVE_STORAGE_KEY)
}

function readProgressSave() {
  return readStorageJSON(PROGRESS_SAVE_STORAGE_KEY)
}

function writeProgressSave(save) {
  writeStorageJSON(PROGRESS_SAVE_STORAGE_KEY, save)
}

function readCompleteSave() {
  return readStorageJSON(COMPLETE_SAVE_STORAGE_KEY)
}

function clearCompleteSave() {
  removeStorageKey(COMPLETE_SAVE_STORAGE_KEY)
}

function writeCompleteSave(completeData) {
  const current = readCompleteSave() || {}
  const next = {
    version: 1,
    completed: true,
    secretPhotoVisible: true,
    endingUnlocked: true,
    endingViewed: false,
    completedAt: Date.now(),
    completedTime: null,
    completedNickname: '',
    rankingPosition: null,
    ...current,
    ...completeData,
  }
  writeStorageJSON(COMPLETE_SAVE_STORAGE_KEY, next)
  return next
}

function countPlacedPiecesInSave(parsed) {
  if (!Array.isArray(parsed?.pieces)) return 0
  return parsed.pieces.reduce((count, piece) => count + (piece?.placed ? 1 : 0), 0)
}

function isCompletedPuzzleState(parsed, expectedPiecesCount = null) {
  if (!parsed || typeof parsed !== 'object') return false

  const explicitComplete = parsed.status === 'completed' || parsed.completed === true || Number.isFinite(parsed.completedAt)
  const endingComplete = typeof parsed.endingStep === 'string' && parsed.endingStep !== 'idle'
  const placedCount = Number.isFinite(parsed.placedCount) ? parsed.placedCount : countPlacedPiecesInSave(parsed)
  const totalPieces = Number.isFinite(expectedPiecesCount)
    ? expectedPiecesCount
    : (Number.isFinite(parsed.piecesCount) ? parsed.piecesCount : Array.isArray(parsed.pieces) ? parsed.pieces.length : 0)
  const allPiecesPlaced = totalPieces > 0 && placedCount >= totalPieces

  return explicitComplete || endingComplete || allPiecesPlaced
}

function isValidProgressSaveShape(parsed, expectedPiecesCount = null) {
  if (!parsed || typeof parsed !== 'object') return false
  if (![1, 2].includes(parsed.version)) return false
  if (!Number.isFinite(parsed.piecesCount)) return false
  if (expectedPiecesCount != null && parsed.piecesCount !== expectedPiecesCount) return false
  if (!Array.isArray(parsed.pieces) || parsed.pieces.length !== parsed.piecesCount) return false
  if (!Number.isFinite(parsed.rows) || !Number.isFinite(parsed.cols)) return false

  const seen = new Set()
  for (const piece of parsed.pieces) {
    if (!piece || typeof piece !== 'object') return false
    if (!Number.isInteger(piece.index) || piece.index < 0 || piece.index >= parsed.piecesCount) return false
    if (seen.has(piece.index)) return false
    seen.add(piece.index)
  }

  return true
}

function hasRestorableProgressSave(expectedPiecesCount) {
  const parsed = readProgressSave()
  if (!parsed) return false
  if (!isValidProgressSaveShape(parsed, expectedPiecesCount)) {
    clearProgressSave()
    return false
  }
  if (isCompletedPuzzleState(parsed, expectedPiecesCount)) {
    clearProgressSave()
    return false
  }
  return true
}

function hasSecretPhotoUnlocked() {
  const completeSave = readCompleteSave()
  if (!completeSave || typeof completeSave !== 'object') return false
  return completeSave.completed === true || completeSave.secretPhotoVisible === true
}

function migrateLegacySaves(expectedPiecesCount) {
  const legacy = readStorageJSON(LEGACY_PUZZLE_STATE_STORAGE_KEY)
  if (!legacy) return

  const hasProgress = !!readProgressSave()
  const hasComplete = !!readCompleteSave()

  if (!isValidProgressSaveShape(legacy)) {
    removeStorageKey(LEGACY_PUZZLE_STATE_STORAGE_KEY)
    return
  }

  if (isCompletedPuzzleState(legacy, expectedPiecesCount)) {
    if (!hasComplete) {
      writeCompleteSave({
        completed: true,
        secretPhotoVisible: true,
        endingUnlocked: true,
        completedAt: Number.isFinite(legacy.completedAt) ? legacy.completedAt : Date.now(),
        completedTime: Number.isFinite(legacy.elapsed) ? legacy.elapsed : null,
        completedNickname: typeof legacy.completedNickname === 'string' ? legacy.completedNickname : '',
      })
    }
    removeStorageKey(LEGACY_PUZZLE_STATE_STORAGE_KEY)
    return
  }

  if (!hasProgress) {
    const migratedProgress = {
      ...legacy,
      version: 2,
      status: 'active',
      completed: false,
      completedAt: null,
    }
    writeProgressSave(migratedProgress)
  }

  removeStorageKey(LEGACY_PUZZLE_STATE_STORAGE_KEY)
}

function makeEdges(rows, cols) {
  const result = []
  for (let row = 0; row < rows; row += 1) {
    for (let col = 0; col < cols; col += 1) {
      const index = row * cols + col
      const top = row === 0 ? 0 : -result[(row - 1) * cols + col].bottom
      const left = col === 0 ? 0 : -result[index - 1].right
      const right = col === cols - 1 ? 0 : Math.random() < 0.5 ? 1 : -1
      const bottom = row === rows - 1 ? 0 : Math.random() < 0.5 ? 1 : -1
      result.push({ top, right, bottom, left })
    }
  }
  return result
}

// sign: 1 = 조각 바깥쪽 돌기, -1 = 안쪽 홈, 0 = 평평한 테두리
function addPiecePath(ctx, x, y, w, h, edges) {
  const tab = Math.min(w, h) * 0.23
  const a = 0.34
  const b = 0.66

  ctx.moveTo(x, y)

  // 위쪽: 왼쪽 → 오른쪽 (바깥쪽은 위)
  ctx.lineTo(x + w * a, y)
  if (edges.top) {
    ctx.bezierCurveTo(
      x + w * 0.39, y - edges.top * tab,
      x + w * 0.61, y - edges.top * tab,
      x + w * b, y,
    )
  }
  ctx.lineTo(x + w, y)

  // 오른쪽: 위 → 아래 (바깥쪽은 오른쪽)
  ctx.lineTo(x + w, y + h * a)
  if (edges.right) {
    ctx.bezierCurveTo(
      x + w + edges.right * tab, y + h * 0.39,
      x + w + edges.right * tab, y + h * 0.61,
      x + w, y + h * b,
    )
  }
  ctx.lineTo(x + w, y + h)

  // 아래쪽: 오른쪽 → 왼쪽 (바깥쪽은 아래)
  ctx.lineTo(x + w * b, y + h)
  if (edges.bottom) {
    ctx.bezierCurveTo(
      x + w * 0.61, y + h + edges.bottom * tab,
      x + w * 0.39, y + h + edges.bottom * tab,
      x + w * a, y + h,
    )
  }
  ctx.lineTo(x, y + h)

  // 왼쪽: 아래 → 위 (바깥쪽은 왼쪽)
  ctx.lineTo(x, y + h * b)
  if (edges.left) {
    ctx.bezierCurveTo(
      x - edges.left * tab, y + h * 0.61,
      x - edges.left * tab, y + h * 0.39,
      x, y + h * a,
    )
  }
  ctx.lineTo(x, y)
  ctx.closePath()
}

function Puzzle({ piecesCount, onComplete, onExit, safeArea }) {
  const canvasRef = useRef(null)
  const wrapRef = useRef(null)
  const imageRef = useRef(null)
  const stateRef = useRef({ pieces: [], drag: null, board: null, rows: 0, cols: 0, nextGroupId: 0 })
  const elapsedRef = useRef(0)
  const [elapsed, setElapsed] = useState(0)
  const [placed, setPlaced] = useState(0)
  const [released, setReleased] = useState(0)
  const [intro, setIntro] = useState(true)
  const [guideEnabled, setGuideEnabled] = useState(false)
  const [dragging, setDragging] = useState(false)
  const [completing, setCompleting] = useState(false)
  const [showCompletionScale, setShowCompletionScale] = useState(false)
  const [showConfetti, setShowConfetti] = useState(false)
  const [showFlash, setShowFlash] = useState(false)
  const completionTimersRef = useRef({ camera: null, scale: null, reveal: null, confettiStart: null, confettiEnd: null, finish: null })
  const [lastRevealPlaying, setLastRevealPlaying] = useState(false)
  const isLastRevealPlayingRef = useRef(false)
  const cameraSoundRef = useRef(null)
  const revealSoundRef = useRef(null)
  const pieceFitSoundRef = useRef(null)
  const pieceFitPoolRef = useRef([])
  const pieceSpawnSoundRef = useRef(null)
  const pieceSpawnPoolRef = useRef([])
  const pieceConnectSoundRef = useRef(null)
  const pieceConnectPoolRef = useRef([])
  const spawnAnimationRAFRef = useRef(null)
  const completionActiveRef = useRef(false)
  const lastPlacementCompletionRef = useRef(false)
  const draggingRef = useRef(false)
  const inputStateRef = useRef({
    mode: 'idle',
    pointerId: null,
    pointerType: null,
    activeGroupId: null,
  })

  function persistPuzzleState(overrides = {}) {
    const state = stateRef.current
    if (!state?.board || !Array.isArray(state.pieces) || state.pieces.length !== piecesCount) return

    const snapshot = {
      version: 2,
      piecesCount,
      rows: state.rows,
      cols: state.cols,
      width: state.width,
      height: state.height,
      elapsed: elapsedRef.current,
      placedCount: state.pieces.filter((piece) => piece.placed).length,
      status: 'active',
      pieces: state.pieces.map((piece) => ({
        index: piece.index,
        x: piece.x,
        y: piece.y,
        released: !!piece.released,
        placed: !!piece.placed,
        groupId: piece.groupId,
      })),
      ...overrides,
    }

    try {
      writeProgressSave(snapshot)
    } catch (error) {}
  }

  function restorePuzzleStateInto(state) {
    const parsed = readProgressSave()
    if (!isValidProgressSaveShape(parsed, piecesCount)) {
      clearProgressSave()
      return false
    }
    if (isCompletedPuzzleState(parsed, piecesCount)) {
      clearProgressSave()
      return false
    }
    if (parsed.rows !== state.rows || parsed.cols !== state.cols) return false
    if (!Array.isArray(parsed.pieces) || parsed.pieces.length !== state.pieces.length) return false

    const savedByIndex = new Map()
    for (const saved of parsed.pieces) {
      if (!saved || typeof saved !== 'object') return false
      if (!Number.isInteger(saved.index)) return false
      if (savedByIndex.has(saved.index)) return false
      savedByIndex.set(saved.index, saved)
    }

    const scaleX = Number.isFinite(parsed.width) && parsed.width > 0 ? state.width / parsed.width : 1
    const scaleY = Number.isFinite(parsed.height) && parsed.height > 0 ? state.height / parsed.height : 1

    for (const piece of state.pieces) {
      const saved = savedByIndex.get(piece.index)
      if (!saved) return false

      const released = !!saved.released
      const placed = !!saved.placed
      const groupId = Number.isInteger(saved.groupId) ? saved.groupId : piece.index

      piece.released = released
      piece.placed = released && placed
      piece.groupId = released ? groupId : piece.index
      piece.spawnedAt = undefined

      if (piece.placed) {
        piece.x = state.board.x + piece.col * piece.w
        piece.y = state.board.y + piece.row * piece.h
        continue
      }

      if (released) {
        const nextX = Number.isFinite(saved.x) ? saved.x * scaleX : piece.x
        const nextY = Number.isFinite(saved.y) ? saved.y * scaleY : piece.y
        piece.x = nextX
        piece.y = nextY
      }
    }

    return true
  }

  useEffect(() => {
    if (intro) return undefined
    const timer = window.setInterval(() => {
      elapsedRef.current += 1
      setElapsed(elapsedRef.current)
    }, 1000)
    return () => window.clearInterval(timer)
  }, [intro])

  useEffect(() => {
    const cameraAudio = new Audio('/sounds/camera.mp3')
    const revealAudio = new Audio('/sounds/reveal.mp3')
    const pieceFitAudio = new Audio(PIECE_FIT_SFX)
    const pieceSpawnAudio = new Audio(PIECE_SPAWN_SFX)
    const pieceConnectAudio = new Audio(PIECE_CONNECT_SFX)
    cameraAudio.preload = 'auto'
    revealAudio.preload = 'auto'
    pieceFitAudio.preload = 'auto'
    pieceSpawnAudio.preload = 'auto'
    pieceConnectAudio.preload = 'auto'
    pieceFitAudio.volume = PIECE_FIT_VOLUME
    pieceSpawnAudio.volume = PIECE_SPAWN_VOLUME
    pieceConnectAudio.volume = PIECE_CONNECT_VOLUME
    cameraSoundRef.current = cameraAudio
    revealSoundRef.current = revealAudio
    pieceFitSoundRef.current = pieceFitAudio
    pieceSpawnSoundRef.current = pieceSpawnAudio
    pieceConnectSoundRef.current = pieceConnectAudio
    pieceFitPoolRef.current = [pieceFitAudio]
    pieceSpawnPoolRef.current = [pieceSpawnAudio]
    pieceConnectPoolRef.current = [pieceConnectAudio]

    return () => {
      if (spawnAnimationRAFRef.current != null) {
        cancelAnimationFrame(spawnAnimationRAFRef.current)
        spawnAnimationRAFRef.current = null
      }
    }
  }, [])

  function createPieceFitAudio() {
    const audio = new Audio(PIECE_FIT_SFX)
    audio.preload = 'auto'
    audio.volume = PIECE_FIT_VOLUME
    return audio
  }

  function getPieceFitAudio() {
    const pool = pieceFitPoolRef.current
    for (const audio of pool) {
      if (audio.paused || audio.ended) return audio
    }
    const nextAudio = createPieceFitAudio()
    pool.push(nextAudio)
    return nextAudio
  }

  function playPieceFitSound() {
    const audio = getPieceFitAudio()
    if (!audio) return
    if (audio.paused || audio.ended) audio.currentTime = 0
    const promise = audio.play()
    if (promise?.catch) promise.catch(() => {})
  }

  function createPieceSpawnAudio() {
    const audio = new Audio(PIECE_SPAWN_SFX)
    audio.preload = 'auto'
    audio.volume = PIECE_SPAWN_VOLUME
    return audio
  }

  function getPieceSpawnAudio() {
    const pool = pieceSpawnPoolRef.current
    for (const audio of pool) {
      if (audio.paused || audio.ended) return audio
    }
    const nextAudio = createPieceSpawnAudio()
    pool.push(nextAudio)
    return nextAudio
  }

  function playPieceSpawnSound() {
    const audio = getPieceSpawnAudio()
    if (!audio) return
    if (audio.paused || audio.ended) audio.currentTime = 0
    const promise = audio.play()
    if (promise?.catch) promise.catch(() => {})
  }

  function cancelSpawnAnimationLoop() {
    if (spawnAnimationRAFRef.current != null) {
      cancelAnimationFrame(spawnAnimationRAFRef.current)
      spawnAnimationRAFRef.current = null
    }
  }

  function startSpawnAnimationLoop() {
    cancelSpawnAnimationLoop()

    const animate = () => {
      const state = stateRef.current
      const now = performance.now()

      draw()

      const activeSpawns = state.pieces.some((piece) => {
        const spawnTime = Number(piece.spawnedAt)
        return Number.isFinite(spawnTime) && now - spawnTime < 220
      })

      if (activeSpawns) {
        spawnAnimationRAFRef.current = requestAnimationFrame(animate)
      } else {
        spawnAnimationRAFRef.current = null
        draw()
      }
    }

    spawnAnimationRAFRef.current = requestAnimationFrame(animate)
  }

  function createPieceConnectAudio() {
    const audio = new Audio(PIECE_CONNECT_SFX)
    audio.preload = 'auto'
    audio.volume = PIECE_CONNECT_VOLUME
    return audio
  }

  function getPieceConnectAudio() {
    const pool = pieceConnectPoolRef.current
    for (const audio of pool) {
      if (audio.paused || audio.ended) return audio
    }
    const nextAudio = createPieceConnectAudio()
    pool.push(nextAudio)
    return nextAudio
  }

  function playPieceConnectSound() {
    const audio = getPieceConnectAudio()
    if (!audio) return
    if (audio.paused || audio.ended) {
      audio.currentTime = 0
    }
    const promise = audio.play()
    if (promise?.catch) promise.catch(() => {})
  }

  useEffect(() => {
    const introTimer = window.setTimeout(() => setIntro(false), 750)
    return () => {
      window.clearTimeout(introTimer)
      Object.values(completionTimersRef.current).forEach((timerId) => window.clearTimeout(timerId))
    }
  }, [])

  useEffect(() => {
    const blockTouchScrollWhileDragging = (event) => {
      const input = inputStateRef.current
      if (input.mode !== 'dragging' || input.pointerType !== 'touch' || !draggingRef.current) return
      event.preventDefault()
    }

    window.addEventListener('touchmove', blockTouchScrollWhileDragging, { passive: false })
    return () => {
      window.removeEventListener('touchmove', blockTouchScrollWhileDragging)
    }
  }, [])

  useEffect(() => {
    const image = new Image()
    image.src = IMG
    image.onload = () => {
      imageRef.current = image
      // Ensure guide is reset when preparing a new game
      setGuideEnabled(false)
      setup()
    }
  }, [piecesCount])

  useEffect(() => {
    normalizeLoosePiecesAroundSafeArea()
  }, [safeArea])

  function clearCompletionTimers() {
    Object.values(completionTimersRef.current).forEach((timerId) => window.clearTimeout(timerId))
    completionTimersRef.current = { camera: null, scale: null, reveal: null, confettiStart: null, confettiEnd: null, finish: null }
  }

  function setup() {
    // Ensure guide is OFF whenever we initialize a new game
    setGuideEnabled(false)
    // reset last piece reveal flags
    isLastRevealPlayingRef.current = false
    setLastRevealPlaying(false)
    clearCompletionTimers()
    completionActiveRef.current = false
    setCompleting(false)
    setShowCompletionScale(false)
    setShowConfetti(false)
    setShowFlash(false)

    const canvas = canvasRef.current
    const wrap = wrapRef.current
    const image = imageRef.current
    if (!canvas || !wrap || !image) return

    elapsedRef.current = 0
    setElapsed(0)

    const dpr = Math.min(window.devicePixelRatio || 1, 2)
    const width = wrap.clientWidth
    const height = Math.max(590, Math.min(window.innerHeight - 125, 900))

    canvas.width = Math.round(width * dpr)
    canvas.height = Math.round(height * dpr)
    canvas.style.width = `${width}px`
    canvas.style.height = `${height}px`

    const [cols, rows] = LEVELS[piecesCount]
    const margin = Math.max(16, Math.min(28, width * 0.025))
    const trayHeight = Math.min(250, height * 0.34)
    const boardAreaHeight = height - trayHeight - margin * 2
    const ratio = image.width / image.height

    let boardWidth = Math.min(width - margin * 2, boardAreaHeight * ratio)
    let boardHeight = boardWidth / ratio
    if (boardHeight > boardAreaHeight) {
      boardHeight = boardAreaHeight
      boardWidth = boardHeight * ratio
    }

    const board = {
      x: (width - boardWidth) / 2,
      y: margin,
      w: boardWidth,
      h: boardHeight,
    }
    const pieceWidth = boardWidth / cols
    const pieceHeight = boardHeight / rows
    const edges = makeEdges(rows, cols)
    const pieces = []
    const padding = Math.min(pieceWidth, pieceHeight) * 0.25
    const trayTop = board.y + board.h + 18
    const trayBottom = height - margin

    for (let row = 0; row < rows; row += 1) {
      for (let col = 0; col < cols; col += 1) {
        const index = row * cols + col
        const minX = margin + padding
        const maxX = Math.max(minX, width - margin - pieceWidth - padding)
        const minY = trayTop + padding
        const maxY = Math.max(minY, trayBottom - pieceHeight - padding)
        pieces.push({
          index,
          row,
          col,
          x: minX + Math.random() * Math.max(1, maxX - minX),
          y: minY + Math.random() * Math.max(1, maxY - minY),
          w: pieceWidth,
          h: pieceHeight,
          placed: false,
          released: false,
          edges: edges[index],
          groupId: index,
        })
      }
    }

    stateRef.current = {
      pieces,
      drag: null,
      board,
      rows,
      cols,
      width,
      height,
      dpr,
      nextGroupId: pieces.length,
      effects: [],
      completionStarted: null,
    }

    const restored = restorePuzzleStateInto(stateRef.current)
    const placedCount = stateRef.current.pieces.filter((piece) => piece.placed).length
    const releasedCount = stateRef.current.pieces.filter((piece) => piece.released).length
    if (!restored) {
      setPlaced(0)
      setReleased(0)
    } else {
      setPlaced(placedCount)
      setReleased(releasedCount)
    }
    draw()
  }

  function drawPlacedPieces(ctx, state, image) {
    const placedPieces = state.pieces.filter((piece) => piece.placed)
    if (placedPieces.length === 0) return

    // 모든 맞춘 조각의 모양을 하나의 마스크로 합친 뒤 사진을 단 한 번만 그림.
    // 그래서 조각 경계의 반투명 안티앨리어싱 틈이 검게 보이지 않음.
    ctx.save()
    ctx.beginPath()
    for (const piece of placedPieces) {
      const x = state.board.x + piece.col * piece.w
      const y = state.board.y + piece.row * piece.h
      addPiecePath(ctx, x, y, piece.w, piece.h, piece.edges)
    }
    ctx.clip()
    ctx.drawImage(image, state.board.x, state.board.y, state.board.w, state.board.h)
    ctx.restore()
  }

  function drawLooseGroup(ctx, state, image, groupPieces, now) {
    if (groupPieces.length === 0) return
    const isDragging = state.drag && state.drag.groupId === groupPieces[0].groupId
    const minX = Math.min(...groupPieces.map((piece) => piece.x))
    const maxX = Math.max(...groupPieces.map((piece) => piece.x + piece.w))
    const minY = Math.min(...groupPieces.map((piece) => piece.y))
    const maxY = Math.max(...groupPieces.map((piece) => piece.y + piece.h))
    const centerX = (minX + maxX) / 2
    const centerY = (minY + maxY) / 2
    const baseScale = isDragging ? 1.035 : 1

    const spawnTime = Number(groupPieces[0].spawnedAt)
    const spawnPiece = groupPieces.length === 1 && Number.isFinite(spawnTime)
    const spawnDuration = 220
    const spawnElapsed = spawnPiece ? Math.max(0, now - spawnTime) : 0
    const isSpawning = spawnPiece && spawnElapsed < spawnDuration
    const spawnProgress = isSpawning ? Math.min(1, spawnElapsed / spawnDuration) : 1
    const spawnScale = isSpawning ? 0.9 + 0.13 * (1 - Math.abs(2 * spawnProgress - 1)) : baseScale
    const spawnTranslateY = isSpawning ? 24 * (1 - spawnProgress) : 0
    const alpha = isSpawning ? Math.min(1, spawnProgress * 1.2) : 1

    ctx.save()
    ctx.translate(centerX, centerY + spawnTranslateY)
    ctx.scale(spawnScale, spawnScale)
    ctx.translate(-centerX, -centerY)
    if (isDragging) {
      ctx.shadowColor = 'rgba(0,0,0,.65)'
      ctx.shadowBlur = 18
      ctx.shadowOffsetY = 8
    } else if (isSpawning) {
      ctx.shadowColor = 'rgba(0,0,0,.35)'
      ctx.shadowBlur = 14 * (1 - spawnProgress)
      ctx.shadowOffsetY = 8 * (1 - spawnProgress)
    }
    ctx.globalAlpha = alpha

    if (isSpawning) {
      const piece = groupPieces[0]
      const dustCount = 3
      const dustBaseX = piece.x + piece.w * 0.45
      const dustBaseY = piece.y + piece.h * 0.22
      const dustTravel = 8 + spawnProgress * 4
      const dustAlpha = Math.max(0, (1 - spawnProgress) * 0.38)
      ctx.save()
      ctx.translate(centerX, centerY + spawnTranslateY)
      ctx.scale(spawnScale, spawnScale)
      ctx.translate(-centerX, -centerY)
      for (let i = 0; i < dustCount; i += 1) {
        const angle = -Math.PI / 2 + (i - 1) * 0.34 + spawnProgress * 0.18
        const offset = dustTravel * (0.85 + i * 0.08)
        const dx = Math.cos(angle) * offset
        const dy = Math.sin(angle) * offset
        const radius = 0.9 + i * 0.4
        ctx.beginPath()
        ctx.fillStyle = `rgba(255,255,255,${dustAlpha * (0.7 + i * 0.1)})`
        ctx.arc(dustBaseX + dx, dustBaseY + dy + spawnProgress * 2, radius, 0, Math.PI * 2)
        ctx.fill()
      }
      ctx.restore()
    }

    ctx.beginPath()
    for (const piece of groupPieces) addPiecePath(ctx, piece.x, piece.y, piece.w, piece.h, piece.edges)
    ctx.clip()
    for (const piece of groupPieces) {
      const imageX = piece.x - piece.col * piece.w
      const imageY = piece.y - piece.row * piece.h
      ctx.drawImage(image, imageX, imageY, state.board.w, state.board.h)
    }
    ctx.restore()

    ctx.save()
    ctx.translate(centerX, centerY + spawnTranslateY)
    ctx.scale(spawnScale, spawnScale)
    ctx.translate(-centerX, -centerY)
    ctx.beginPath()
    for (const piece of groupPieces) addPiecePath(ctx, piece.x, piece.y, piece.w, piece.h, piece.edges)
    ctx.strokeStyle = isDragging ? 'rgba(255,255,255,.95)' : 'rgba(255,255,255,.68)'
    ctx.lineWidth = isDragging ? 1.7 : 1
    ctx.stroke()
    ctx.restore()

    if (spawnPiece && spawnElapsed >= spawnDuration) {
      groupPieces[0].spawnedAt = undefined
    }
  }

  function draw() {
    const canvas = canvasRef.current
    const image = imageRef.current
    const state = stateRef.current
    if (!canvas || !image || !state.board) return

    const ctx = canvas.getContext('2d')
    ctx.setTransform(state.dpr, 0, 0, state.dpr, 0, 0)
    ctx.clearRect(0, 0, state.width, state.height)

    // 퍼즐이 완성되기 전에는 원본 이미지를 바닥에 절대 깔지 않음.
    ctx.fillStyle = '#0b0d15'
    ctx.fillRect(0, 0, state.width, state.height)

    const completionElapsed = state.completionStarted == null
      ? 0
      : (performance.now() - state.completionStarted)
    const completionProgress = Math.min(1, completionElapsed / 1600)

    ctx.fillStyle = '#10131d'
    ctx.fillRect(state.board.x, state.board.y, state.board.w, state.board.h)
    if (completionElapsed < 400) {
      const borderAlpha = 0.20 * (1 - (completionElapsed / 400))
      ctx.strokeStyle = `rgba(255,255,255,${borderAlpha})`
      ctx.lineWidth = 1
      ctx.setLineDash([7, 7])
      ctx.strokeRect(state.board.x, state.board.y, state.board.w, state.board.h)
      ctx.setLineDash([])
    }

    if (guideEnabled) {
      ctx.save()
      ctx.strokeStyle = 'rgba(255,255,255,0.16)'
      ctx.lineWidth = 0.9
      for (const piece of state.pieces) {
        const x = state.board.x + piece.col * piece.w
        const y = state.board.y + piece.row * piece.h
        ctx.beginPath()
        addPiecePath(ctx, x, y, piece.w, piece.h, piece.edges)
        ctx.stroke()
      }
      ctx.restore()
    }

    // 자석 결합 순간의 짧은 파동 효과
    const now = performance.now()
    state.effects = (state.effects || []).filter((effect) => now - effect.started < 360)
    for (const effect of state.effects) {
      const progress = Math.min(1, (now - effect.started) / 360)
      ctx.beginPath()
      ctx.arc(effect.x, effect.y, 8 + progress * 28, 0, Math.PI * 2)
      ctx.strokeStyle = `rgba(255,255,255,${0.75 * (1 - progress)})`
      ctx.lineWidth = 2
      ctx.stroke()
    }

    drawPlacedPieces(ctx, state, image)

    const loosePieces = state.pieces.filter((piece) => piece.released && !piece.placed)
    const groupOrder = []
    const groups = new Map()
    for (const piece of loosePieces) {
      if (!groups.has(piece.groupId)) {
        groups.set(piece.groupId, [])
        groupOrder.push(piece.groupId)
      }
      groups.get(piece.groupId).push(piece)
    }
    const dragGroupId = state.drag?.groupId
    for (const groupId of groupOrder) {
      if (groupId !== dragGroupId) drawLooseGroup(ctx, state, image, groups.get(groupId), now)
    }
    if (dragGroupId != null && groups.has(dragGroupId)) {
      drawLooseGroup(ctx, state, image, groups.get(dragGroupId), now)
    }
  }

  useEffect(() => {
    draw()
  }, [guideEnabled])

  function triggerCompletion({ isTest = false } = {}) {
    if (completionActiveRef.current) return
    completionActiveRef.current = true
    writeCompleteSave({
      completed: true,
      secretPhotoVisible: true,
      endingUnlocked: true,
      completedAt: Date.now(),
      completedTime: elapsedRef.current,
    })
    clearProgressSave()
    setCompleting(true)
    setShowCompletionScale(true)
    setShowConfetti(false)
    stateRef.current.completionStarted = performance.now()

    const playAudio = (audioRef) => {
      if (!audioRef?.current) return
      audioRef.current.currentTime = 0
      audioRef.current.play().catch(() => {})
    }

    clearCompletionTimers()
    const cameraDelay = !isTest && lastPlacementCompletionRef.current ? CAMERA_DELAY_AFTER_PIECE_FIT : 0
    if (cameraDelay > 0) {
      completionTimersRef.current.camera = window.setTimeout(() => {
        setShowFlash(true)
        playAudio(cameraSoundRef)
        completionTimersRef.current.camera = window.setTimeout(() => setShowFlash(false), 180)
      }, cameraDelay)
    } else {
      setShowFlash(true)
      playAudio(cameraSoundRef)
      completionTimersRef.current.camera = window.setTimeout(() => setShowFlash(false), 180)
    }
    completionTimersRef.current.scale = window.setTimeout(() => setShowCompletionScale(false), 400)
    completionTimersRef.current.reveal = window.setTimeout(() => {
      playAudio(revealSoundRef)
    }, 250)
    completionTimersRef.current.confettiStart = window.setTimeout(() => setShowConfetti(true), 1250)
    completionTimersRef.current.confettiEnd = window.setTimeout(() => setShowConfetti(false), 4250)
    completionTimersRef.current.finish = window.setTimeout(() => {
      onComplete(elapsedRef.current)
      if (isTest) {
        completionActiveRef.current = false
      }
    }, 650)

    const animate = () => {
      draw()
      if (completionActiveRef.current) requestAnimationFrame(animate)
    }
    requestAnimationFrame(animate)
  }

  function releasePieces() {
    const state = stateRef.current
    if (!state.board) return
    const safeRect = getSafeAreaInCanvas(state)

    const hidden = state.pieces.filter((piece) => !piece.released)
    if (hidden.length === 0) return

    // If exactly one hidden piece remains, play the special last-piece reveal
    if (hidden.length === 1) {
      const lastPiece = hidden[0]
      // prevent double-trigger
      if (!isLastRevealPlayingRef.current) {
        // temporarily disable regular spawning and play special reveal
        playLastPieceReveal(lastPiece)
      }
      return
    }

    const batchSize = 10
    const selectCount = hidden.length <= batchSize ? Math.max(1, hidden.length - 1) : batchSize
    const shuffled = [...hidden].sort(() => Math.random() - 0.5)
    const selected = shuffled.slice(0, selectCount)
    const spawnTime = performance.now()

    const board = state.board
    const margin = Math.max(14, Math.min(26, state.width * 0.025))
    const topGap = board.y + margin
    const bottomAreaY = board.y + board.h + margin
    const bottomAreaHeight = state.height - bottomAreaY - margin
    const leftAreaWidth = board.x - margin * 2
    const rightAreaX = board.x + board.w + margin
    const rightAreaWidth = state.width - rightAreaX - margin

    const regions = []
    if (leftAreaWidth >= 1) {
      regions.push({ id: 'left', x: margin, y: topGap, w: leftAreaWidth, h: state.height - topGap - margin })
    }
    if (rightAreaWidth >= 1) {
      regions.push({ id: 'right', x: rightAreaX, y: topGap, w: rightAreaWidth, h: state.height - topGap - margin })
    }
    if (bottomAreaHeight >= 1) {
      regions.push({ id: 'bottom', x: margin, y: bottomAreaY, w: state.width - margin * 2, h: bottomAreaHeight })
    }
    if (regions.length === 0) {
      regions.push({ id: 'bottom', x: margin, y: bottomAreaY, w: Math.max(1, state.width - margin * 2), h: Math.max(1, state.height - bottomAreaY - margin) })
    }

    const activePieces = state.pieces.filter((piece) => piece.released && !piece.placed)

    const getRegionCount = (region) => activePieces.filter((piece) => {
      const centerX = piece.x + piece.w * 0.5
      const centerY = piece.y + piece.h * 0.5
      return centerX >= region.x && centerX <= region.x + region.w && centerY >= region.y && centerY <= region.y + region.h
    }).length

    const regionCounts = regions.map((region) => ({ region, count: getRegionCount(region) }))

    const orderByCount = () => regionCounts.slice().sort((a, b) => a.count - b.count)

    const getOverlapScore = (x, y, piece) => {
      let score = 0
      for (const other of activePieces) {
        if (other === piece) continue
        const overlapX = Math.max(0, Math.min(x + piece.w, other.x + other.w) - Math.max(x, other.x))
        const overlapY = Math.max(0, Math.min(y + piece.h, other.y + other.h) - Math.max(y, other.y))
        if (overlapX > 0 && overlapY > 0) {
          score += overlapX * overlapY
        }
      }
      if (safeRect && rectsOverlap({ left: x, top: y, right: x + piece.w, bottom: y + piece.h }, safeRect)) {
        score += state.width * state.height
      }
      return score
    }

    for (const piece of selected) {
      const sortedRegions = orderByCount()
      const region = sortedRegions[0].region
      sortedRegions[0].count += 1

      const maxX = Math.max(region.x, region.x + region.w - piece.w)
      const maxY = Math.max(region.y, region.y + region.h - piece.h)
      let best = null

      for (let attempt = 0; attempt < 18; attempt += 1) {
        const candidateX = region.x + Math.random() * (maxX - region.x)
        const candidateY = region.y + Math.random() * (maxY - region.y)
        let nextX = candidateX
        let nextY = candidateY
        if (safeRect) {
          const escape = getSafeAreaEscapeDelta(
            { left: nextX, top: nextY, right: nextX + piece.w, bottom: nextY + piece.h },
            safeRect,
            state,
          )
          if (escape && (escape.dx || escape.dy)) {
            nextX += escape.dx
            nextY += escape.dy
          }
        }

        const score = getOverlapScore(nextX, nextY, piece)
        if (best === null || score < best.score) {
          best = { x: nextX, y: nextY, score }
          if (score === 0) break
        }
      }

      piece.x = best?.x ?? region.x
      piece.y = best?.y ?? region.y
      piece.released = true
      piece.spawnedAt = spawnTime
      activePieces.push(piece)
    }

    setReleased(state.pieces.filter((piece) => piece.released).length)
    persistPuzzleState()
    window.setTimeout(() => playPieceSpawnSound(), 40)
    draw()
    startSpawnAnimationLoop()
  }

  // Helper to trigger the special last-piece reveal animation for a single piece
  function playLastPieceReveal(piece) {
    if (!piece || isLastRevealPlayingRef.current) return
    isLastRevealPlayingRef.current = true
    setLastRevealPlaying(true)

    const audio = getPieceSpawnAudio()
    // slight pre-delay and gentle volume bump
    const originalVolume = audio.volume
    audio.volume = Math.min(1, (originalVolume || 0.5) + 0.06)

    // small sequence of timeouts for reveal choreography
    // 1) short darken and text
    // 2) particles
    // 3) spawn piece
    const revealStart = performance.now()

    // show overlay for ~800ms and then release piece
    window.setTimeout(() => {
      // actually reveal the piece (mark released and set spawn time)
      piece.released = true
      piece.spawnedAt = performance.now()
      keepGroupOutOfSafeArea(stateRef.current, piece.groupId)
      setReleased((s) => s + 1)
      // play spawn sound (slightly louder)
      try {
        audio.currentTime = 0
        const p = audio.play()
        if (p?.catch) p.catch(() => {})
      } catch (e) {}
      // cleanup
      audio.volume = originalVolume
      isLastRevealPlayingRef.current = false
      setLastRevealPlaying(false)
      persistPuzzleState()
      draw()
      startSpawnAnimationLoop()
    }, 800)
  }

  function pointerPosition(event) {
    const canvas = canvasRef.current
    if (!canvas) return { x: 0, y: 0 }
    const rect = canvas.getBoundingClientRect()
    const x = event.offsetX != null ? event.offsetX : event.clientX - rect.left
    const y = event.offsetY != null ? event.offsetY : event.clientY - rect.top
    return { x, y }
  }

  function isInsidePiece(ctx, piece, point, pointerType = 'mouse') {
    const padding = Math.min(piece.w, piece.h) * (pointerType === 'touch' ? 0.36 : 0.22)
    if (
      point.x < piece.x - padding ||
      point.x > piece.x + piece.w + padding ||
      point.y < piece.y - padding ||
      point.y > piece.y + piece.h + padding
    ) return false

    ctx.save()
    ctx.beginPath()
    addPiecePath(ctx, piece.x, piece.y, piece.w, piece.h, piece.edges)
    const isPathHit = ctx.isPointInPath(point.x, point.y)
    ctx.restore()

    if (isPathHit) return true
    if (pointerType !== 'touch') return false

    const centerX = piece.x + piece.w * 0.5
    const centerY = piece.y + piece.h * 0.5
    const distance = Math.hypot(point.x - centerX, point.y - centerY)
    const fallbackRadius = Math.min(piece.w, piece.h) * 0.38
    return distance <= fallbackRadius
  }

  function choosePieceForPointer(state, point, pointerType) {
    const canvas = canvasRef.current
    if (!canvas) return null
    const ctx = canvas.getContext('2d')

    if (pointerType !== 'touch') {
      for (let index = state.pieces.length - 1; index >= 0; index -= 1) {
        const piece = state.pieces[index]
        if (!piece.released || piece.placed) continue
        if (isInsidePiece(ctx, piece, point, pointerType)) return piece
      }
      return null
    }

    const groupSizes = new Map()
    for (const piece of state.pieces) {
      if (!piece.released || piece.placed) continue
      groupSizes.set(piece.groupId, (groupSizes.get(piece.groupId) || 0) + 1)
    }

    let bestPiece = null
    let bestScore = -Infinity
    for (let index = state.pieces.length - 1; index >= 0; index -= 1) {
      const piece = state.pieces[index]
      if (!piece.released || piece.placed) continue
      const bboxPadding = Math.min(piece.w, piece.h) * 0.42
      if (
        point.x < piece.x - bboxPadding ||
        point.x > piece.x + piece.w + bboxPadding ||
        point.y < piece.y - bboxPadding ||
        point.y > piece.y + piece.h + bboxPadding
      ) continue

      ctx.save()
      ctx.beginPath()
      addPiecePath(ctx, piece.x, piece.y, piece.w, piece.h, piece.edges)
      const isPathHit = ctx.isPointInPath(point.x, point.y)
      ctx.restore()

      const centerX = piece.x + piece.w * 0.5
      const centerY = piece.y + piece.h * 0.5
      const distance = Math.hypot(point.x - centerX, point.y - centerY)
      const maxDistance = Math.min(piece.w, piece.h) * 0.55
      if (!isPathHit && distance > maxDistance) continue

      const groupSize = groupSizes.get(piece.groupId) || 1
      const topness = index / Math.max(1, state.pieces.length)
      const score = (isPathHit ? 100000 : 0) - (distance * 10) - (groupSize * 4) + topness
      if (score > bestScore) {
        bestScore = score
        bestPiece = piece
      }
    }

    return bestPiece
  }

  function resetInputState() {
    draggingRef.current = false
    inputStateRef.current = {
      mode: 'idle',
      pointerId: null,
      pointerType: null,
      activeGroupId: null,
    }
  }

  function startDragForGroup(state, pointerId, groupId, point, pointerType) {
    bringGroupToFront(state, groupId)
    const touchLift = pointerType === 'touch' ? 14 : 0
    if (touchLift) moveGroup(state, groupId, 0, -touchLift, true)
    state.drag = {
      groupId,
      lastX: point.x,
      lastY: point.y,
    }
    setDragging(true)
    draggingRef.current = true
    const canvas = canvasRef.current
    if (canvas?.setPointerCapture) {
      try {
        canvas.setPointerCapture(pointerId)
      } catch (error) {}
    }
    draw()
  }

  function groupPieces(state, groupId) {
    return state.pieces.filter((piece) => piece.groupId === groupId && !piece.placed)
  }

  function bringGroupToFront(state, groupId) {
    const moving = state.pieces.filter((piece) => piece.groupId === groupId)
    state.pieces = state.pieces.filter((piece) => piece.groupId !== groupId)
    state.pieces.push(...moving)
  }

  function moveGroup(state, groupId, dx, dy, keepInside = false) {
    const members = groupPieces(state, groupId)
    if (members.length === 0) return

    let safeDx = dx
    let safeDy = dy
    if (keepInside) {
      const padding = Math.min(members[0].w, members[0].h) * 0.24
      const minX = Math.min(...members.map((piece) => piece.x - padding))
      const maxX = Math.max(...members.map((piece) => piece.x + piece.w + padding))
      const minY = Math.min(...members.map((piece) => piece.y - padding))
      const maxY = Math.max(...members.map((piece) => piece.y + piece.h + padding))
      safeDx = Math.max(-minX + 4, Math.min(safeDx, state.width - maxX - 4))
      safeDy = Math.max(-minY + 4, Math.min(safeDy, state.height - maxY - 4))
    }

    for (const piece of members) {
      piece.x += safeDx
      piece.y += safeDy
    }
  }

  function getGroupBounds(members) {
    return {
      left: Math.min(...members.map((piece) => piece.x)),
      right: Math.max(...members.map((piece) => piece.x + piece.w)),
      top: Math.min(...members.map((piece) => piece.y)),
      bottom: Math.max(...members.map((piece) => piece.y + piece.h)),
    }
  }

  function rectsOverlap(rectA, rectB) {
    return !(
      rectA.right <= rectB.left ||
      rectA.left >= rectB.right ||
      rectA.bottom <= rectB.top ||
      rectA.top >= rectB.bottom
    )
  }

  function getSafeAreaInCanvas(state) {
    if (!safeArea) return null
    const canvas = canvasRef.current
    if (!canvas || !state?.width || !state?.height) return null

    const rect = canvas.getBoundingClientRect()
    const padding = 10
    const left = Math.max(0, safeArea.left - rect.left - padding)
    const top = Math.max(0, safeArea.top - rect.top - padding)
    const right = Math.min(state.width, safeArea.right - rect.left + padding)
    const bottom = Math.min(state.height, safeArea.bottom - rect.top + padding)

    if (right <= left || bottom <= top) return null
    return { left, top, right, bottom }
  }

  function getSafeAreaEscapeDelta(bounds, safeRect, state) {
    if (!safeRect || !rectsOverlap(bounds, safeRect)) return { dx: 0, dy: 0 }

    const gap = 8
    const options = [
      { dx: (safeRect.left - gap) - bounds.right, dy: 0 },
      { dx: (safeRect.right + gap) - bounds.left, dy: 0 },
      { dx: 0, dy: (safeRect.top - gap) - bounds.bottom },
      { dx: 0, dy: (safeRect.bottom + gap) - bounds.top },
    ]

    const feasible = options.filter(({ dx, dy }) => (
      bounds.left + dx >= 4 &&
      bounds.right + dx <= state.width - 4 &&
      bounds.top + dy >= 4 &&
      bounds.bottom + dy <= state.height - 4
    ))

    const candidates = feasible.length > 0 ? feasible : options
    return candidates.reduce((best, option) => {
      const distance = Math.abs(option.dx) + Math.abs(option.dy)
      if (!best || distance < best.distance) return { ...option, distance }
      return best
    }, null)
  }

  function keepGroupOutOfSafeArea(state, groupId) {
    const safeRect = getSafeAreaInCanvas(state)
    if (!safeRect) return false

    const members = groupPieces(state, groupId)
    if (members.length === 0) return false

    const bounds = getGroupBounds(members)
    if (!rectsOverlap(bounds, safeRect)) return false

    const escape = getSafeAreaEscapeDelta(bounds, safeRect, state)
    if (!escape || (!escape.dx && !escape.dy)) return false

    moveGroup(state, groupId, escape.dx, escape.dy, true)
    return true
  }

  function normalizeLoosePiecesAroundSafeArea() {
    const state = stateRef.current
    if (!state?.board || draggingRef.current) return

    const looseGroupIds = [...new Set(
      state.pieces
        .filter((piece) => piece.released && !piece.placed)
        .map((piece) => piece.groupId)
    )]

    let changed = false
    for (const groupId of looseGroupIds) {
      changed = keepGroupOutOfSafeArea(state, groupId) || changed
    }

    if (changed) {
      persistPuzzleState()
      draw()
    }
  }

  function snapFeedback(state, members) {
    if (!members?.length) return
    if (navigator.vibrate) navigator.vibrate(22)
    draw()
  }

  function tryMergeWithNeighbour(state, draggedGroupId) {
    const dragged = groupPieces(state, draggedGroupId)
    if (dragged.length === 0) return draggedGroupId
    const snapDistance = Math.max(12, Math.min(dragged[0].w, dragged[0].h) * 0.42)

    for (const piece of dragged) {
      const neighbours = [
        [piece.row, piece.col - 1, -piece.w, 0],
        [piece.row, piece.col + 1, piece.w, 0],
        [piece.row - 1, piece.col, 0, -piece.h],
        [piece.row + 1, piece.col, 0, piece.h],
      ]

      for (const [row, col, relX, relY] of neighbours) {
        if (row < 0 || row >= state.rows || col < 0 || col >= state.cols) continue
        const neighbour = state.pieces.find((item) => item.row === row && item.col === col)
        if (!neighbour || neighbour.placed || !neighbour.released || neighbour.groupId === draggedGroupId) continue

        const wantedX = neighbour.x - relX
        const wantedY = neighbour.y - relY
        if (Math.hypot(piece.x - wantedX, piece.y - wantedY) > snapDistance) continue

        moveGroup(state, draggedGroupId, wantedX - piece.x, wantedY - piece.y)
        const targetGroupId = neighbour.groupId
        for (const member of groupPieces(state, draggedGroupId)) member.groupId = targetGroupId
        bringGroupToFront(state, targetGroupId)
        playPieceConnectSound()
        snapFeedback(state, groupPieces(state, targetGroupId))
        return targetGroupId
      }
    }
    return draggedGroupId
  }

  function tryPlaceGroupOnBoard(state, groupId) {
    const members = groupPieces(state, groupId)
    if (members.length === 0) return false
    const snapDistance = Math.max(18, Math.min(members[0].w, members[0].h) * 0.72)

    let anchor = null
    for (const piece of members) {
      const targetX = state.board.x + piece.col * piece.w
      const targetY = state.board.y + piece.row * piece.h
      if (Math.hypot(piece.x - targetX, piece.y - targetY) <= snapDistance) {
        anchor = { piece, targetX, targetY }
        break
      }
    }
    if (!anchor) return false

    moveGroup(state, groupId, anchor.targetX - anchor.piece.x, anchor.targetY - anchor.piece.y)
    const placedPieces = groupPieces(state, groupId)
    for (const piece of placedPieces) {
      piece.placed = true
      piece.x = state.board.x + piece.col * piece.w
      piece.y = state.board.y + piece.row * piece.h
    }
    playPieceFitSound()
    snapFeedback(state, members)
    return true
  }

  function handlePointerDown(event) {
    if (intro) return

    const input = inputStateRef.current
    if (input.mode === 'dragging' && input.pointerId !== event.pointerId) {
      return
    }

    if (event.pointerType === 'touch' && event.isPrimary === false) {
      return
    }

    const state = stateRef.current
    const point = pointerPosition(event)
    const piece = choosePieceForPointer(state, point, event.pointerType)
    if (!piece) {
      return
    }

    event.preventDefault()
    startDragForGroup(state, event.pointerId, piece.groupId, point, event.pointerType)
    inputStateRef.current = {
      mode: 'dragging',
      pointerId: event.pointerId,
      pointerType: event.pointerType,
      activeGroupId: piece.groupId,
    }
  }

  function handlePointerMove(event) {
    const state = stateRef.current
    const input = inputStateRef.current

    if (input.pointerId != null && input.pointerId !== event.pointerId) return

    if (!state.drag || input.mode !== 'dragging') return
    event.preventDefault()
    const point = pointerPosition(event)
    moveGroup(state, state.drag.groupId, point.x - state.drag.lastX, point.y - state.drag.lastY, true)
    state.drag.lastX = point.x
    state.drag.lastY = point.y
    draw()
  }

  function handlePointerUp(event) {
    const input = inputStateRef.current
    if (input.pointerId != null && input.pointerId !== event.pointerId) return

    const state = stateRef.current
    if (!state.drag || input.mode !== 'dragging') {
      resetInputState()
      return
    }

    event.preventDefault()

    let groupId = state.drag.groupId
    // 한 번 놓을 때 연쇄적으로 여러 묶음이 붙을 수 있도록 반복 검사함.
    let previous
    do {
      previous = groupId
      groupId = tryMergeWithNeighbour(state, groupId)
    } while (groupId !== previous)

    tryPlaceGroupOnBoard(state, groupId)
    if (!state.pieces.some((piece) => piece.groupId === groupId && piece.placed)) {
      keepGroupOutOfSafeArea(state, groupId)
    }

    const placedCount = state.pieces.filter((item) => item.placed).length
    const isFinalPlacement = placedCount === state.pieces.length
    setPlaced(placedCount)
    if (isFinalPlacement) {
      lastPlacementCompletionRef.current = true
      triggerCompletion({ isTest: false })
    } else {
      lastPlacementCompletionRef.current = false
    }

    persistPuzzleState()

    state.drag = null
    setDragging(false)
    draggingRef.current = false
    if (canvasRef.current.hasPointerCapture?.(event.pointerId)) {
      canvasRef.current.releasePointerCapture(event.pointerId)
    }
    resetInputState()
    draw()
  }

  function applyDevInstantCompleteState() {
    const state = stateRef.current
    if (!state?.board || !state?.pieces?.length) return

    isLastRevealPlayingRef.current = false
    setLastRevealPlaying(false)

    for (const piece of state.pieces) {
      piece.released = true
      piece.placed = true
      piece.spawnedAt = undefined
      piece.x = state.board.x + piece.col * piece.w
      piece.y = state.board.y + piece.row * piece.h
    }

    setReleased(state.pieces.length)
    setPlaced(state.pieces.length)
    persistPuzzleState()
    draw()
  }

  return (
    <div className={`game-screen ${completing ? 'is-completing' : ''}`}>
      <header className="game-header">
        <b>Mu:uM Hidden Piece</b>
        <div className="top-pills">
          <button type="button" className="guide-toggle-button" onClick={() => setGuideEnabled((value) => !value)}>
            {guideEnabled ? '가이드 ON' : '가이드 OFF'}
          </button>
          <span className="time-pill" aria-live="off">{fmt(elapsed)}</span>
          <button type="button" onClick={onExit}>나가기</button>
        </div>
      </header>
      <div className="progress-wrap">
        {!intro && released < piecesCount && (
          <button type="button" className="bag-button" onClick={releasePieces}>
            <span className="bag-center">
              <span aria-hidden="true">🧩</span>
              <span>조각 뽑기</span>
            </span>
            <span className="bag-count">×{piecesCount - released}</span>
          </button>
        )}
        <div className="progress-info">{placed} / {piecesCount} <span className="progress-percent">· {Math.round((placed / piecesCount) * 100)}%</span></div>
        <div className="progress-track" aria-hidden="true">
          <div className="progress-fill" style={{ width: `${Math.min(100, Math.round((placed / piecesCount) * 100))}%` }} />
        </div>
      </div>
      <div className={`canvas-wrap ${dragging ? 'is-dragging' : ''} ${showCompletionScale ? 'is-scaling' : ''}`} ref={wrapRef}>
          {intro && (
          <div className="puzzle-intro" aria-label="퍼즐 준비 중">
            <div className="intro-bag" aria-hidden="true">🧩</div>
            <strong>Mu:uM Hidden Piece</strong>
            <span>조각을 꺼내 퍼즐을 시작하세요</span>
          </div>
        )}
        {showFlash && (
          <div className="camera-flash" aria-hidden="true" />
        )}
        <canvas
          ref={canvasRef}
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
          onPointerCancel={handlePointerUp}
          onLostPointerCapture={handlePointerUp}
        />
        {lastRevealPlaying && (
          <div className={`last-reveal-overlay visible`}>
            <div className="last-reveal-badge">마지막 조각</div>
            <div className="last-reveal-particles" aria-hidden="true">
              {Array.from({ length: 8 }).map((_, i) => (
                <i key={i} className="last-reveal-particle" style={{ left: `${12 + i * 9}%`, top: `${48 + (i % 3) * 6}%`, animationDelay: `${i * 60}ms` }} />
              ))}
            </div>
          </div>
        )}
        {import.meta.env.DEV && !intro && !completing && (
          <button
            type="button"
            className="dev-complete-button"
            onClick={() => {
              applyDevInstantCompleteState()
              triggerCompletion({ isTest: true })
            }}
          >
            즉시 완료
          </button>
        )}
      </div>
    </div>
  )
}

export default function App() {
  const [screen, setScreen] = useState('start')
  const [count] = useState(PUZZLE_PIECES)
  const [record, setRecord] = useState(0)
  const [name, setName] = useState('')
  const [ranking, setRanking] = useState(() => JSON.parse(localStorage.getItem('muum-ranking') || '[]'))
  const audioRef = useRef(null)
  const queueRef = useRef([])
  const queuePositionRef = useRef(0)
  const currentTrackRef = useRef(null)
  const playedHistoryRef = useRef([])
  const [musicStarted, setMusicStarted] = useState(false)
  const [currentTrack, setCurrentTrack] = useState(null)
  const [isPlaying, setIsPlaying] = useState(false)
  const [muted, setMuted] = useState(false)
  const [gameSession, setGameSession] = useState(0)
  const [hasProgressSave, setHasProgressSave] = useState(() => hasRestorableProgressSave(PUZZLE_PIECES))
  const [completeSave, setCompleteSave] = useState(() => readCompleteSave())
  const [playerOpen, setPlayerOpen] = useState(false)
  const playerRef = useRef(null)
  const [playerSafeArea, setPlayerSafeArea] = useState(null)
  const [trackVisible, setTrackVisible] = useState(true)
  const [endingStep, setEndingStep] = useState('idle')
  const [endingEnterDisabled, setEndingEnterDisabled] = useState(false)
  const [endingHomeDisabled, setEndingHomeDisabled] = useState(false)
  const endingTimersRef = useRef([])
  const endingFadeRafRef = useRef(null)
  const endingRunTokenRef = useRef(0)
  const doorOpenSoundRef = useRef(null)
  const footStepSoundRef = useRef(null)
  const endingEnterLockedRef = useRef(false)

  const refreshSaveIndicators = () => {
    setHasProgressSave(hasRestorableProgressSave(count))
    setCompleteSave(readCompleteSave())
  }

  const getRankingPosition = (nickname, timeValue) => {
    if (!nickname || !Number.isFinite(timeValue)) return null
    const index = ranking.findIndex((item) => item.name === nickname && item.time === timeValue)
    return index >= 0 ? index + 1 : null
  }

  const clearEndingTimers = () => {
    for (const timerId of endingTimersRef.current) {
      window.clearTimeout(timerId)
    }
    endingTimersRef.current = []
  }

  const stopEndingFadeRaf = () => {
    if (endingFadeRafRef.current != null) {
      window.cancelAnimationFrame(endingFadeRafRef.current)
      endingFadeRafRef.current = null
    }
  }

  const resetEndingState = () => {
    clearEndingTimers()
    stopEndingFadeRaf()
    if (doorOpenSoundRef.current) {
      doorOpenSoundRef.current.pause()
      doorOpenSoundRef.current.currentTime = 0
    }
    if (footStepSoundRef.current) {
      footStepSoundRef.current.pause()
      footStepSoundRef.current.currentTime = 0
    }
    endingEnterLockedRef.current = false
    setEndingEnterDisabled(false)
    setEndingHomeDisabled(false)
    setEndingStep('idle')
  }

  const scheduleEnding = (callback, delay) => {
    const timerId = window.setTimeout(callback, delay)
    endingTimersRef.current.push(timerId)
  }

  const fadeOutBgmOver = (durationMs, token) => {
    const audio = audioRef.current
    if (!audio || audio.paused) return

    const initialVolume = Number.isFinite(audio.volume) ? Math.max(0, Math.min(1, audio.volume)) : 0.65
    if (initialVolume <= 0.001) {
      audio.pause()
      setIsPlaying(false)
      audio.volume = 0.65
      return
    }

    const startedAt = performance.now()
    const tick = (now) => {
      if (token !== endingRunTokenRef.current) return

      const progress = Math.min(1, (now - startedAt) / durationMs)
      audio.volume = initialVolume * (1 - progress)

      if (progress < 1) {
        endingFadeRafRef.current = window.requestAnimationFrame(tick)
        return
      }

      audio.pause()
      setIsPlaying(false)
      audio.volume = 0.65
      endingFadeRafRef.current = null
    }

    stopEndingFadeRaf()
    endingFadeRafRef.current = window.requestAnimationFrame(tick)
  }

  const triggerEndingSequence = () => {
    if (screen !== 'complete' && screen !== 'photo') return
    if (endingStep !== 'idle') return

    resetEndingState()
    const token = endingRunTokenRef.current + 1
    endingRunTokenRef.current = token

    setEndingStep('fade-start')
    setEndingHomeDisabled(false)
    fadeOutBgmOver(1000, token)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('fade')
    }, 30)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('black-hold')
    }, 1000)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('door-message')
      const doorAudio = doorOpenSoundRef.current
      if (doorAudio) {
        doorAudio.currentTime = 0
        const promise = doorAudio.play()
        if (promise?.catch) promise.catch(() => {})
      }
    }, 3000)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('door-enter')
    }, 5000)
  }

  const playDoorOpenAndProceed = () => {
    if (endingStep !== 'door-enter') return
    if (endingEnterLockedRef.current) return
    endingEnterLockedRef.current = true
    setEndingEnterDisabled(true)
    setEndingStep('walking')

    const token = endingRunTokenRef.current
    const audio = footStepSoundRef.current || new Audio(FOOT_STEP_SFX)
    if (!footStepSoundRef.current) {
      audio.preload = 'auto'
      footStepSoundRef.current = audio
    }

    let done = false
    const finishDoorStep = () => {
      if (done) return
      done = true
      audio.removeEventListener('ended', onEnded)
      beginPostDoorFade(token)
    }

    const onEnded = () => {
      finishDoorStep()
    }

    audio.addEventListener('ended', onEnded)
    audio.currentTime = 0
    const promise = audio.play()
    if (promise?.catch) {
      promise.catch(() => {
        finishDoorStep()
      })
    }

    scheduleEnding(() => {
      finishDoorStep()
    }, 2500)
  }

  const beginPostDoorFade = (token) => {
    if (token !== endingRunTokenRef.current) return
    setEndingStep('after-foot-hold')

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('white-orb-appear')
    }, 800)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('white-orb-grow')
    }, 1600)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('white-orb-peak')
    }, 4100)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('navy-fade')
    }, 4900)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('navy-rest')
    }, 6400)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('final-coming')
    }, 7400)

    // Coming Soon fade-in 1.5s + 1.2s hold
    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('final-title')
    }, 10100)

    // Mu:uM Escape Game fade-in 1.2s + 1.0s hold
    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('final-handle')
    }, 12300)

    // @band fade-in 1.0s + 1.5s hold
    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('final-home')
    }, 14800)
  }

  const exitHiddenEndingToStart = () => {
    if (endingHomeDisabled) return
    setEndingHomeDisabled(true)
    const token = endingRunTokenRef.current + 1
    endingRunTokenRef.current = token
    setEndingStep('exit-start')

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      setEndingStep('exiting')
    }, 30)

    scheduleEnding(() => {
      if (token !== endingRunTokenRef.current) return
      writeCompleteSave({ endingViewed: true, endingUnlocked: true })
      setName('')
      setGameSession((value) => value + 1)
      refreshSaveIndicators()
      setScreen('start')
    }, 830)
  }

  useEffect(() => {
    const doorAudio = new Audio(DOOR_OPEN_SFX)
    const footAudio = new Audio(FOOT_STEP_SFX)
    doorAudio.preload = 'auto'
    footAudio.preload = 'auto'
    doorOpenSoundRef.current = doorAudio
    footStepSoundRef.current = footAudio
    return () => {
      if (doorOpenSoundRef.current) {
        doorOpenSoundRef.current.pause()
        doorOpenSoundRef.current.currentTime = 0
      }
      if (footStepSoundRef.current) {
        footStepSoundRef.current.pause()
        footStepSoundRef.current.currentTime = 0
      }
      resetEndingState()
    }
  }, [])

  useEffect(() => {
    const audio = audioRef.current
    if (!audio) return
    audio.volume = 0.65
    audio.muted = muted
  }, [muted])

  useEffect(() => {
    migrateLegacySaves(count)
    refreshSaveIndicators()
  }, [count])

  useEffect(() => {
    if (screen === 'start') {
      refreshSaveIndicators()
    }
  }, [screen])

  const loadTrack = (trackIndex, shouldPlay = true, recordHistory = true) => {
    const audio = audioRef.current
    if (!audio) return
    if (recordHistory && currentTrackRef.current != null && currentTrackRef.current !== trackIndex) {
      playedHistoryRef.current.push(currentTrackRef.current)
      // cap history to reasonable length
      if (playedHistoryRef.current.length > 200) playedHistoryRef.current.shift()
    }
    currentTrackRef.current = trackIndex
    setCurrentTrack(trackIndex)
    audio.src = TRACKS[trackIndex].src
    audio.load()
    if (shouldPlay) {
      const promise = audio.play()
      if (promise?.catch) promise.catch(() => setIsPlaying(false))
    }
  }

  const startMusic = () => {
    const queue = shuffledIndexes()
    queueRef.current = queue
    queuePositionRef.current = 0
    playedHistoryRef.current = []
    setMusicStarted(true)
    loadTrack(queue[0], true, false)
  }

  const selectTrack = (trackIndex) => {
    const audio = audioRef.current
    if (!audio) return

    if (!musicStarted) {
      setMusicStarted(true)
    }

    if (queueRef.current.includes(trackIndex)) {
      queuePositionRef.current = queueRef.current.indexOf(trackIndex)
    } else {
      const queue = shuffledIndexes(trackIndex)
      queueRef.current = queue
      queuePositionRef.current = 0
    }

    // record selection in history
    if (currentTrackRef.current != null && currentTrackRef.current !== trackIndex) {
      playedHistoryRef.current.push(currentTrackRef.current)
    }
    currentTrackRef.current = trackIndex
    setCurrentTrack(trackIndex)
    audio.src = TRACKS[trackIndex].src
    audio.load()
    audio.play().catch(() => setIsPlaying(false))
    setPlayerOpen(true)
  }

  const nextTrack = () => {
    if (!musicStarted) return
    // push current into history
    if (currentTrackRef.current != null) {
      playedHistoryRef.current.push(currentTrackRef.current)
      if (playedHistoryRef.current.length > 200) playedHistoryRef.current.shift()
    }
    let queue = queueRef.current
    let nextPosition = queuePositionRef.current + 1
    if (nextPosition >= queue.length) {
      queue = shuffledIndexes(currentTrackRef.current)
      queueRef.current = queue
      nextPosition = 0
    }
    queuePositionRef.current = nextPosition
    loadTrack(queue[nextPosition], true, false)
  }

  const previousTrack = () => {
    if (!musicStarted) return
    const audio = audioRef.current
    if (audio?.currentTime > 4) {
      audio.currentTime = 0
      audio.play().catch(() => setIsPlaying(false))
      return
    }
    // if we have a played history, go to the last actually played track
    const hist = playedHistoryRef.current
    if (hist.length > 0) {
      const prev = hist.pop()
      // try to sync queuePosition if present
      const idx = queueRef.current.indexOf(prev)
      if (idx >= 0) queuePositionRef.current = idx
      loadTrack(prev, true, false)
      return
    }
    let previousPosition = queuePositionRef.current - 1
    if (previousPosition < 0) previousPosition = queueRef.current.length - 1
    queuePositionRef.current = previousPosition
    loadTrack(queueRef.current[previousPosition], true, false)
  }

  const pauseBgmForExit = () => {
    const audio = audioRef.current
    if (!audio) return
    if (!audio.paused) {
      audio.pause()
    }
    setIsPlaying(false)
  }

  const togglePlay = () => {
    const audio = audioRef.current
    if (!audio || !musicStarted) return
    if (audio.paused) audio.play().catch(() => setIsPlaying(false))
    else audio.pause()
  }

  useEffect(() => {
    if (screen === 'start' || screen === 'ranking') {
      pauseBgmForExit()
    }
  }, [screen])

  useEffect(() => {
    endingRunTokenRef.current += 1
    resetEndingState()
  }, [screen])

  useEffect(() => {
    if (screen === 'start') {
      setPlayerOpen(false)
    }
  }, [screen])

  useEffect(() => {
    setTrackVisible(false)
    const timeout = window.setTimeout(() => setTrackVisible(true), 20)
    return () => window.clearTimeout(timeout)
  }, [currentTrack])

  useEffect(() => {
    if (!playerOpen) return undefined
    const handleOutsideClick = (event) => {
      if (playerRef.current && !playerRef.current.contains(event.target)) {
        setPlayerOpen(false)
      }
    }
    document.addEventListener('pointerdown', handleOutsideClick)
    return () => document.removeEventListener('pointerdown', handleOutsideClick)
  }, [playerOpen])

  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') {
        pauseBgmForExit()
      }
    }

    const handlePageHide = () => {
      pauseBgmForExit()
    }

    const handlePopState = () => {
      pauseBgmForExit()
    }

    window.addEventListener('visibilitychange', handleVisibilityChange)
    window.addEventListener('pagehide', handlePageHide)
    window.addEventListener('popstate', handlePopState)

    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange)
      window.removeEventListener('pagehide', handlePageHide)
      window.removeEventListener('popstate', handlePopState)
    }
  }, [])

  const complete = (time) => {
    clearProgressSave()
    writeCompleteSave({
      completed: true,
      secretPhotoVisible: true,
      endingUnlocked: true,
      completedAt: Date.now(),
      completedTime: time,
    })
    setRecord(time)
    refreshSaveIndicators()
    setScreen('complete')
  }

  const save = () => {
    if (!name.trim()) return
    const trimmedName = name.trim()
    const next = [...ranking, {
      name: trimmedName,
      time: record,
      date: new Date().toLocaleDateString(),
    }].sort((a, b) => a.time - b.time).slice(0, 50)

    const rankingPosition = next.findIndex((item) => item.name === trimmedName && item.time === record)
    writeCompleteSave({
      completedNickname: trimmedName,
      completedTime: record,
      rankingPosition: rankingPosition >= 0 ? rankingPosition + 1 : null,
      secretPhotoVisible: true,
    })

    setRanking(next)
    localStorage.setItem('muum-ranking', JSON.stringify(next))
    const clearTimeMs = Math.max(0, Math.round(record * 1000))
    void fetch('/api/rankings', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        nickname: trimmedName,
        clearTimeMs,
        gameVersion: '1.0.0'
      })
    })
      .then(async (response) => {
        if (response.ok) return
        let body = ''
        try {
          body = await response.text()
        } catch (error) {}
        console.error('[ranking] POST /api/rankings failed', {
          status: response.status,
          body,
        })
      })
      .catch((error) => {
        console.error('[ranking] POST /api/rankings error', error)
      })
    refreshSaveIndicators()
    endingRunTokenRef.current += 1
    resetEndingState()
    setScreen('ranking')
  }

  const ensureMusicForGame = () => {
    if (!musicStarted) startMusic()
    else audioRef.current?.play().catch(() => setIsPlaying(false))
  }

  const startNewGameFromStartScreen = () => {
    clearProgressSave()
    endingRunTokenRef.current += 1
    resetEndingState()
    setRecord(0)
    setName('')
    setGameSession((value) => value + 1)
    refreshSaveIndicators()
    ensureMusicForGame()
    setScreen('game')
  }

  const continueSavedGameFromStartScreen = () => {
    if (!hasRestorableProgressSave(count)) {
      refreshSaveIndicators()
      startNewGameFromStartScreen()
      return
    }
    endingRunTokenRef.current += 1
    resetEndingState()
    setGameSession((value) => value + 1)
    ensureMusicForGame()
    setScreen('game')
  }

  const openSecretPhotoView = () => {
    const saved = readCompleteSave()
    if (!saved || !hasSecretPhotoUnlocked()) return

    if (Number.isFinite(saved.completedTime)) {
      setRecord(saved.completedTime)
    }
    if (typeof saved.completedNickname === 'string' && saved.completedNickname.trim()) {
      setName(saved.completedNickname.trim())
    }
    endingRunTokenRef.current += 1
    resetEndingState()
    setScreen('photo')
  }

  useEffect(() => {
    if (screen !== 'game') {
      setPlayerSafeArea(null)
      return undefined
    }

    const shell = playerRef.current
    if (!shell) {
      setPlayerSafeArea(null)
      return undefined
    }

    const measureSafeArea = () => {
      if (window.innerWidth > 760) {
        setPlayerSafeArea(null)
        return
      }

      const logo = shell.querySelector('.muum-logo-btn')
      const panel = playerOpen ? shell.querySelector('.muum-panel.visible') : null
      const rects = [logo, panel]
        .filter(Boolean)
        .map((node) => node.getBoundingClientRect())
        .filter((rect) => rect.width > 0 && rect.height > 0)

      if (rects.length === 0) {
        setPlayerSafeArea(null)
        return
      }

      const left = Math.min(...rects.map((rect) => rect.left))
      const top = Math.min(...rects.map((rect) => rect.top))
      const right = Math.max(...rects.map((rect) => rect.right))
      const bottom = Math.max(...rects.map((rect) => rect.bottom))
      setPlayerSafeArea({ left, top, right, bottom, width: right - left, height: bottom - top })
    }

    const scheduleMeasure = () => window.requestAnimationFrame(measureSafeArea)
    scheduleMeasure()

    const resizeObserver = typeof ResizeObserver === 'function' ? new ResizeObserver(scheduleMeasure) : null
    if (resizeObserver) {
      resizeObserver.observe(shell)
      const logo = shell.querySelector('.muum-logo-btn')
      const panel = shell.querySelector('.muum-panel')
      if (logo) resizeObserver.observe(logo)
      if (panel) resizeObserver.observe(panel)
    }

    window.addEventListener('resize', scheduleMeasure)
    shell.addEventListener('transitionend', scheduleMeasure)

    return () => {
      window.removeEventListener('resize', scheduleMeasure)
      shell.removeEventListener('transitionend', scheduleMeasure)
      resizeObserver?.disconnect()
    }
  }, [screen, playerOpen])

  let content
  if (screen === 'game') {
    content = <Puzzle key={gameSession} piecesCount={count} onComplete={complete} onExit={() => setScreen('start')} safeArea={playerSafeArea} />
  } else if (screen === 'complete' || screen === 'photo') {
    const isPhotoView = screen === 'photo'
    const photoName = completeSave?.completedNickname?.trim() || '-'
    const rankingPosition = Number.isFinite(completeSave?.rankingPosition) ? completeSave.rankingPosition : getRankingPosition(photoName === '-' ? null : photoName, record)
    content = (
      <main className="complete-screen">
        <div className="confetti" aria-hidden="true">
          {Array.from({ length: 42 }, (_, index) => <i key={index} style={{ '--i': index }} />)}
        </div>
        <div className="complete-card">
          <div className="complete-hero">
            <p className="complete-kicker">MISSION COMPLETE</p>
            <p className="complete-subtitle">야생의 뮤움을 발견했다!</p>
          </div>
          <div className="complete-image-wrap complete-media">
            <img src={IMG} alt="완성된 비밀 사진" />
            <span className="sparkle sparkle-one">✦</span>
            <span className="sparkle sparkle-two">✧</span>
            <span className="sparkle sparkle-three">✦</span>
          </div>
          <div className="complete-summary">
            <p className="record-label">완성 기록</p>
            <strong className="record-time">{fmt(record)}</strong>
            {!isPhotoView ? (
              <div className="nickname-row">
                <input value={name} onChange={(event) => setName(event.target.value)} maxLength={12} placeholder="닉네임" />
                <button type="button" onClick={save}>랭킹 등록</button>
              </div>
            ) : (
              <div className="photo-meta" role="status" aria-live="polite">
                <p>완료 닉네임: {photoName}</p>
                <p>{rankingPosition ? `랭킹 ${rankingPosition}위` : '랭킹 정보 없음'}</p>
              </div>
            )}
          </div>
          <div className="complete-actions">
            {!isPhotoView ? (
              <>
                <button type="button" className="replay-button" onClick={() => { endingRunTokenRef.current += 1; resetEndingState(); clearProgressSave(); setGameSession((value) => value + 1); setName(''); refreshSaveIndicators(); setScreen('game') }}>PLAY AGAIN</button>
                <button type="button" onClick={() => { endingRunTokenRef.current += 1; resetEndingState(); setScreen('start') }}>메인으로</button>
                <button type="button" className="hidden-ending-trigger" onClick={triggerEndingSequence}>...</button>
              </>
            ) : (
              <>
                <button type="button" className="replay-button" onClick={triggerEndingSequence}>ENDING 다시 보기</button>
                <button type="button" onClick={() => { endingRunTokenRef.current += 1; resetEndingState(); setScreen('start') }}>메인으로</button>
              </>
            )}
          </div>
        </div>
      </main>
    )
  } else if (screen === 'ranking') {
    content = (
      <main className="ranking-screen">
        <div className="ranking-card">
          <h1>RANKING</h1>
          {ranking.map((item, index) => (
            <div className="rank" key={`${item.name}-${item.time}-${index}`}>
              <b>{index + 1}</b>
              <span>{item.name}</span>
              <em>{fmt(item.time)}</em>
            </div>
          ))}
          <button type="button" onClick={() => setScreen('start')}>처음으로</button>
        </div>
      </main>
    )
  } else {
    content = (
      <main className="start-screen">
        <div className="background-image" />
        <div className="background-overlay" />
        <section className="start-content">
          <h1 className="logo">Mu:uM</h1>
          <div className="divider" />
          <h2>HIDDEN PIECE</h2>
          <p className="game-description">모든 조각을 맞추는 순간,<br />비밀이 모습을 드러냅니다.</p>
          <div className="start-actions start-main-actions">
            {hasProgressSave && (
              <button type="button" className="start-button" onClick={continueSavedGameFromStartScreen}>CONTINUE</button>
            )}
            <button type="button" className="start-button" onClick={startNewGameFromStartScreen}>NEW GAME</button>
            <button type="button" className="text-button" onClick={() => setScreen('ranking')}>RANKING</button>
          </div>
          {hasSecretPhotoUnlocked() && (
            <div className="hidden-secret-section" aria-label="Secret Photo Section">
              <div className="hidden-secret-separator" aria-hidden="true" />
              <button type="button" className="start-button" onClick={openSecretPhotoView}>SECRET PHOTO</button>
              <div className="hidden-secret-separator" aria-hidden="true" />
            </div>
          )}
        </section>
        <div className="start-version-label" aria-hidden="true">{APP_VERSION_LABEL}</div>
      </main>
    )
  }

  return (
    <>
      <audio
        ref={audioRef}
        preload="metadata"
        onEnded={nextTrack}
        onPlay={() => setIsPlaying(true)}
        onPause={() => setIsPlaying(false)}
      />

      {screen === 'game' && (
        <div className={`muum-player-shell ${playerOpen ? 'open' : 'closed'}`} ref={playerRef} aria-hidden={false}>
          <button
            type="button"
            className={`muum-logo-btn`}
            style={{display: 'inline-flex', padding: 0, boxSizing: 'border-box'}}
            onClick={() => {
              if (!musicStarted) startMusic()
              setPlayerOpen((v) => !v)
            }}
            onKeyDown={(e) => {
              if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault()
                if (!musicStarted) startMusic()
                setPlayerOpen((v) => !v)
              }
            }}
            aria-label={playerOpen ? '음악 플레이어 닫기' : '음악 플레이어 열기'}
            aria-expanded={playerOpen}
          >
            <img src="/muum-logo.png" alt="Mu:uM" draggable="false" />
          </button>

          <aside className={`muum-panel ${playerOpen ? 'visible' : ''}`} role="dialog" aria-hidden={!playerOpen}>
            <header className="muum-panel-header">
              <div className="muum-now">
                <span className="muum-now-label">NOW PLAYING</span>
                <strong className={`muum-track ${trackVisible ? 'visible' : 'hidden'}`}>{TRACKS[currentTrack]?.title}</strong>
                <small>Mu:uM</small>
              </div>
              <button type="button" className="muum-close" onClick={() => setPlayerOpen(false)} aria-label="접기">×</button>
            </header>

            <div className="muum-controls">
              <button type="button" className="icon" onClick={previousTrack} aria-label="이전 곡">
                <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M15.41 7.41 10.83 12l4.58 4.59L14 18l-6-6 6-6z" fill="currentColor"/></svg>
              </button>
              <button type="button" className="icon" onClick={togglePlay} aria-label={isPlaying ? '일시정지' : '재생'}>
                {isPlaying ? (
                  <svg viewBox="0 0 24 24" aria-hidden="true"><rect x="6" y="5" width="4" height="14" rx="1" fill="currentColor"/><rect x="14" y="5" width="4" height="14" rx="1" fill="currentColor"/></svg>
                ) : (
                  <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M8 5v14l11-7L8 5z" fill="currentColor"/></svg>
                )}
              </button>
              <button type="button" className="icon" onClick={nextTrack} aria-label="다음 곡">
                <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M8.59 16.59 13.17 12 8.59 7.41 10 6l6 6-6 6z" fill="currentColor"/></svg>
              </button>
              <button type="button" className="icon" onClick={() => setMuted((v)=>!v)} aria-label={muted ? '음소거 해제' : '음소거'}>
                {muted ? (
                  <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M5 9v6h4l5 4V5L9 9H5z" fill="currentColor"/><path d="M18 8l4 4m0-4l-4 4" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>
                ) : (
                  <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M5 9v6h4l5 4V5L9 9H5z" fill="currentColor"/></svg>
                )}
              </button>
            </div>
          </aside>
        </div>
      )}

      {(screen === 'complete' || screen === 'photo') && endingStep !== 'idle' && (
        <div
          className={`teaser-overlay ${endingStep !== 'fade-start' ? 'is-darkening' : ''} ${endingStep === 'exiting' ? 'is-exiting' : ''} ${(endingStep === 'navy-fade' || endingStep === 'navy-rest' || endingStep === 'final-coming' || endingStep === 'final-title' || endingStep === 'final-handle' || endingStep === 'final-home' || endingStep === 'exit-start' || endingStep === 'exiting') ? 'is-navy-ending' : ''}`}
          aria-live="polite"
        >
          {(endingStep === 'white-orb-appear' || endingStep === 'white-orb-grow' || endingStep === 'white-orb-peak' || endingStep === 'navy-fade') && (
            <div
              className={`teaser-white-bloom ${endingStep === 'white-orb-appear' ? 'is-appear' : ''} ${endingStep === 'white-orb-grow' ? 'is-grow' : ''} ${endingStep === 'white-orb-peak' ? 'is-peak' : ''} ${endingStep === 'navy-fade' ? 'is-fading' : ''}`}
              aria-hidden="true"
            />
          )}

          {endingStep === 'walking' && (
            <div className="teaser-atmosphere is-walking" aria-hidden="true">
              <div className="teaser-glow" />
              <div className="teaser-dust-layer">
                {Array.from({ length: 12 }).map((_, index) => (
                  <i
                    key={index}
                    className="teaser-dust"
                    style={{
                      '--x': `${18 + (index * 7) % 64}%`,
                      '--y': `${34 + (index * 5) % 30}%`,
                      '--d': `${index * 240}ms`,
                      '--t': `${5.8 + (index % 5) * 1.1}s`,
                      '--s': `${1.2 + (index % 3) * 0.7}px`,
                    }}
                  />
                ))}
              </div>
            </div>
          )}

          <div className="teaser-center">
            {(endingStep === 'door-message' || endingStep === 'door-enter' || endingStep === 'walking') && (
              <p className="teaser-sentence">■■■의 문이 열렸습니다.</p>
            )}

            {endingStep === 'door-enter' && (
              <div className="teaser-enter-wrap-inline">
                <button type="button" className="teaser-enter-link" onClick={playDoorOpenAndProceed} disabled={endingEnterDisabled}>
                  <span>들어가기</span>
                  <span aria-hidden="true">→</span>
                </button>
              </div>
            )}

            {(endingStep === 'final-coming' || endingStep === 'final-title' || endingStep === 'final-handle' || endingStep === 'final-home' || endingStep === 'exit-start' || endingStep === 'exiting') && (
              <div className="teaser-final-block">
                <p className="teaser-line teaser-coming">Coming Soon</p>
                {(endingStep === 'final-title' || endingStep === 'final-handle' || endingStep === 'final-home' || endingStep === 'exit-start' || endingStep === 'exiting') && (
                  <p className="teaser-line teaser-title">Mu:uM Escape Game</p>
                )}
                {(endingStep === 'final-handle' || endingStep === 'final-home' || endingStep === 'exit-start' || endingStep === 'exiting') && (
                  <p className="teaser-line teaser-handle">@band_mu.um</p>
                )}
                {(endingStep === 'final-home' || endingStep === 'exit-start' || endingStep === 'exiting') && (
                  <button
                    type="button"
                    className="teaser-home-button"
                    onClick={exitHiddenEndingToStart}
                    disabled={endingHomeDisabled}
                  >
                    처음으로
                  </button>
                )}
              </div>
            )}
          </div>
        </div>
      )}

      {content}
    </>
  )
}
